-- Testimonials table for Super CTA Responder
create table if not exists testimonials (
  id           uuid primary key default gen_random_uuid(),
  quote        text not null,
  customer_details text,
  case_study_url   text,
  sector       text not null,  -- k12 | higher_edu | vocational | corporate | utilities | museum | manufacturing | ngo
  segment      text not null,  -- education | business
  created_at   timestamptz default now()
);

-- Index for sector lookups
create index if not exists testimonials_sector_idx on testimonials (sector);

